import{_ as d,o as r,c as a,a2 as h}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"审核前文件请求清单","description":"","frontmatter":{},"headers":[],"relativePath":"zh/templates/audit-checklist.md","filePath":"zh/templates/audit-checklist.md"}'),e={name:"zh/templates/audit-checklist.md"};function o(l,t,b,i,n,c){return r(),a("div",null,[...t[0]||(t[0]=[h('<h1 id="审核前文件请求清单" tabindex="-1">审核前文件请求清单 <a class="header-anchor" href="#审核前文件请求清单" aria-label="Permalink to &quot;审核前文件请求清单&quot;">​</a></h1><blockquote><p><strong>使用说明：</strong> 请在现场审核开始前<strong>至少30天</strong>将对应清单发送给供应商，并说明文件的提交格式（PDF扫描件/原件备查）、提交截止日期和提交方式。收到文件后应先进行案头审查（Desk Review），再前往现场核实原件。</p></blockquote><hr><h2 id="清单一-社会责任-csr-审核文件请求清单" tabindex="-1">清单一：社会责任（CSR）审核文件请求清单 <a class="header-anchor" href="#清单一-社会责任-csr-审核文件请求清单" aria-label="Permalink to &quot;清单一：社会责任（CSR）审核文件请求清单&quot;">​</a></h2><p>适用审核标准：amfori BSCI / SMETA / SA8000 / 本公司CSR标准</p><h3 id="a-企业基本文件" tabindex="-1">A. 企业基本文件 <a class="header-anchor" href="#a-企业基本文件" aria-label="Permalink to &quot;A. 企业基本文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th><th>备注</th></tr></thead><tbody><tr><td>A1</td><td>营业执照（正/副本）</td><td>核查注册信息、经营范围、有效期</td><td>须为现行有效版本</td></tr><tr><td>A2</td><td>组织机构代码证 / 统一社会信用代码证明</td><td></td><td></td></tr><tr><td>A3</td><td>工厂平面图（含疏散路线图）</td><td>用于验证实地观察与图纸一致性</td><td></td></tr><tr><td>A4</td><td>组织架构图</td><td>含各部门负责人姓名和职位</td><td></td></tr><tr><td>A5</td><td>主要客户名单（可匿名处理）</td><td></td><td></td></tr></tbody></table><h3 id="b-劳工文件" tabindex="-1">B. 劳工文件 <a class="header-anchor" href="#b-劳工文件" aria-label="Permalink to &quot;B. 劳工文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th><th>备注</th></tr></thead><tbody><tr><td>B1</td><td>员工花名册</td><td>含姓名、出生日期、入职日期、岗位、合同类型</td><td>审核当月数据；须含所有类型员工（正式工、派遣工、实习生）</td></tr><tr><td>B2</td><td>劳动合同样本</td><td>须含正式工、派遣工各一份</td><td>提交模板；现场抽查原件</td></tr><tr><td>B3</td><td>过去3个月工资单（含加班费明细）</td><td>核查工资发放合规性</td><td>按5-10名随机工人抽样</td></tr><tr><td>B4</td><td>过去3个月考勤记录</td><td>核查实际工作时间</td><td>须含刷卡记录或考勤系统原始数据</td></tr><tr><td>B5</td><td>社保缴纳证明（过去3个月）</td><td>核查社保覆盖率和足额缴纳</td><td>须含缴纳明细，非仅总金额</td></tr><tr><td>B6</td><td>未成年工（15-18岁）名册（如有）</td><td></td><td>须含健康检查记录</td></tr><tr><td>B7</td><td>劳务派遣/外包服务合同（如有）</td><td>核查派遣机构资质及责任划分</td><td></td></tr><tr><td>B8</td><td>工资制度/员工手册</td><td>核查政策合规性</td><td></td></tr><tr><td>B9</td><td>工会/员工代表委员会相关文件（如有）</td><td></td><td></td></tr></tbody></table><h3 id="c-职业健康与安全文件" tabindex="-1">C. 职业健康与安全文件 <a class="header-anchor" href="#c-职业健康与安全文件" aria-label="Permalink to &quot;C. 职业健康与安全文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th><th>备注</th></tr></thead><tbody><tr><td>C1</td><td>安全生产许可证（如适用）</td><td></td><td></td></tr><tr><td>C2</td><td>职业病危害申报文件（如适用）</td><td></td><td></td></tr><tr><td>C3</td><td>化学品清单与SDS（安全数据表）</td><td>须覆盖所有在用化学品</td><td></td></tr><tr><td>C4</td><td>工伤事故记录（过去12个月）</td><td></td><td>含事故报告和调查记录</td></tr><tr><td>C5</td><td>消防检查记录和消防设备维护台账</td><td></td><td></td></tr><tr><td>C6</td><td>应急预案和疏散演练记录（过去12个月）</td><td></td><td></td></tr><tr><td>C7</td><td>员工健康检查记录（如有）</td><td>特别是接触危险物质的岗位</td><td></td></tr><tr><td>C8</td><td>OHS培训记录</td><td></td><td></td></tr></tbody></table><h3 id="d-管理体系文件" tabindex="-1">D. 管理体系文件 <a class="header-anchor" href="#d-管理体系文件" aria-label="Permalink to &quot;D. 管理体系文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th><th>备注</th></tr></thead><tbody><tr><td>D1</td><td>社会责任/可持续发展政策（书面版本）</td><td></td><td></td></tr><tr><td>D2</td><td>员工申诉渠道说明文件</td><td></td><td></td></tr><tr><td>D3</td><td>前次审核报告和整改行动计划（CAP）</td><td></td><td>用于跟踪上次审核发现项</td></tr><tr><td>D4</td><td>企业社会责任培训记录（过去12个月）</td><td></td><td></td></tr></tbody></table><hr><h2 id="清单二-环境合规审核文件请求清单" tabindex="-1">清单二：环境合规审核文件请求清单 <a class="header-anchor" href="#清单二-环境合规审核文件请求清单" aria-label="Permalink to &quot;清单二：环境合规审核文件请求清单&quot;">​</a></h2><p>适用：年度环境合规审核；ISO 14001认证准备；客户或监管要求的环境审核</p><h3 id="a-环境许可与合规文件" tabindex="-1">A. 环境许可与合规文件 <a class="header-anchor" href="#a-环境许可与合规文件" aria-label="Permalink to &quot;A. 环境许可与合规文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>EA1</td><td>排污许可证（正本）</td><td>核查有效期、许可排放量和许可条件</td></tr><tr><td>EA2</td><td>环境影响评价批复（&quot;环评&quot;）</td><td>特别是近期扩建或新增产线须有对应环评</td></tr><tr><td>EA3</td><td>&quot;三同时&quot;验收报告</td><td>须与现行生产状况一致</td></tr><tr><td>EA4</td><td>危险废物经营许可证（如自行处置）</td><td></td></tr><tr><td>EA5</td><td>辐射安全许可证（如适用）</td><td></td></tr></tbody></table><h3 id="b-污染物监测记录" tabindex="-1">B. 污染物监测记录 <a class="header-anchor" href="#b-污染物监测记录" aria-label="Permalink to &quot;B. 污染物监测记录&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>EB1</td><td>废水排放监测报告（过去12个月）</td><td>须含各项指标与标准对照</td></tr><tr><td>EB2</td><td>废气排放监测报告（过去12个月）</td><td>特别是有燃烧设备、喷涂工艺的工厂</td></tr><tr><td>EB3</td><td>噪音检测报告（过去24个月）</td><td></td></tr><tr><td>EB4</td><td>在线监控数据摘要（如安装了在线监控设备）</td><td></td></tr></tbody></table><h3 id="c-废弃物管理记录" tabindex="-1">C. 废弃物管理记录 <a class="header-anchor" href="#c-废弃物管理记录" aria-label="Permalink to &quot;C. 废弃物管理记录&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>EC1</td><td>固体废弃物分类处置台账（过去12个月）</td><td>含各类别废弃物数量和处置方式</td></tr><tr><td>EC2</td><td>危险废物转移联单（过去12个月）</td><td>须与台账一致</td></tr><tr><td>EC3</td><td>危险废物处置单位资质证书（复印件）</td><td></td></tr></tbody></table><h3 id="d-能源与水资源数据" tabindex="-1">D. 能源与水资源数据 <a class="header-anchor" href="#d-能源与水资源数据" aria-label="Permalink to &quot;D. 能源与水资源数据&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>ED1</td><td>近3年度电力消耗记录（电费单或电表数据）</td><td></td></tr><tr><td>ED2</td><td>近3年度用水量记录</td><td></td></tr><tr><td>ED3</td><td>近3年度燃料消耗记录（天然气/柴油/煤等，如适用）</td><td></td></tr><tr><td>ED4</td><td>温室气体排放数据或碳核查报告（如已编制）</td><td></td></tr><tr><td>ED5</td><td>可再生能源使用证明（如有：绿证、光伏合同等）</td><td></td></tr></tbody></table><h3 id="e-管理体系文件" tabindex="-1">E. 管理体系文件 <a class="header-anchor" href="#e-管理体系文件" aria-label="Permalink to &quot;E. 管理体系文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>EE1</td><td>环境管理体系文件（ISO 14001认证证书，如有）</td><td></td></tr><tr><td>EE2</td><td>环保政策和环保目标文件</td><td></td></tr><tr><td>EE3</td><td>环保培训记录（过去12个月）</td><td></td></tr><tr><td>EE4</td><td>环境事故记录（过去24个月）</td><td></td></tr><tr><td>EE5</td><td>前次环保检查/审核报告及整改记录</td><td></td></tr></tbody></table><hr><h2 id="清单三-供应链安全与网络安全审核文件请求清单" tabindex="-1">清单三：供应链安全与网络安全审核文件请求清单 <a class="header-anchor" href="#清单三-供应链安全与网络安全审核文件请求清单" aria-label="Permalink to &quot;清单三：供应链安全与网络安全审核文件请求清单&quot;">​</a></h2><p>适用：C-TPAT/AEO审核；客户网络安全评估；ISO 27001/ISO 28000准备</p><h3 id="a-物理安全" tabindex="-1">A. 物理安全 <a class="header-anchor" href="#a-物理安全" aria-label="Permalink to &quot;A. 物理安全&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>SA1</td><td>工厂/仓库安全管理制度</td><td>含进出人员管理、车辆管理</td></tr><tr><td>SA2</td><td>门禁系统管理记录（过去3个月样本）</td><td></td></tr><tr><td>SA3</td><td>访客登记台账（过去3个月样本）</td><td></td></tr><tr><td>SA4</td><td>CCTV监控覆盖范围示意图</td><td></td></tr><tr><td>SA5</td><td>安保人员培训记录</td><td></td></tr><tr><td>SA6</td><td>货物篡改/异常检查程序（书面）</td><td></td></tr><tr><td>SA7</td><td>AEO认证证书（如适用）</td><td></td></tr></tbody></table><h3 id="b-信息安全" tabindex="-1">B. 信息安全 <a class="header-anchor" href="#b-信息安全" aria-label="Permalink to &quot;B. 信息安全&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>SB1</td><td>信息安全管理政策（书面）</td><td></td></tr><tr><td>SB2</td><td>ISO 27001认证证书（如有）</td><td></td></tr><tr><td>SB3</td><td>最近一次渗透测试报告或漏洞扫描报告（摘要版）</td><td>可提供无敏感技术细节的版本</td></tr><tr><td>SB4</td><td>信息安全培训记录（过去12个月）</td><td></td></tr><tr><td>SB5</td><td>安全事件记录（过去12个月）</td><td>含已关闭的事件</td></tr><tr><td>SB6</td><td>灾难恢复/业务连续性计划（BCP/DRP，摘要）</td><td></td></tr><tr><td>SB7</td><td>用户账号管理制度（含离职账号注销流程）</td><td></td></tr><tr><td>SB8</td><td>如有软件/固件产品，提供SBOM或软件成分分析摘要</td><td></td></tr></tbody></table><h3 id="c-数据合规" tabindex="-1">C. 数据合规 <a class="header-anchor" href="#c-数据合规" aria-label="Permalink to &quot;C. 数据合规&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>SC1</td><td>数据保护/隐私政策</td><td></td></tr><tr><td>SC2</td><td>数据处理活动记录（ROPA，如GDPR适用）</td><td></td></tr><tr><td>SC3</td><td>数据安全影响评估（DPIA，如处理大量敏感数据）</td><td></td></tr><tr><td>SC4</td><td>跨境数据传输相关文件（标准合同条款/CBPR等，如适用）</td><td></td></tr><tr><td>SC5</td><td>数据泄露事件记录（过去12个月）</td><td></td></tr></tbody></table><hr><h2 id="清单四-知识产权合规审核文件请求清单" tabindex="-1">清单四：知识产权合规审核文件请求清单 <a class="header-anchor" href="#清单四-知识产权合规审核文件请求清单" aria-label="Permalink to &quot;清单四：知识产权合规审核文件请求清单&quot;">​</a></h2><p>适用：供应商IP合规年度审核；新供应商高风险IP评估</p><h3 id="a-ip管理制度文件" tabindex="-1">A. IP管理制度文件 <a class="header-anchor" href="#a-ip管理制度文件" aria-label="Permalink to &quot;A. IP管理制度文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>IA1</td><td>知识产权管理制度（书面）</td><td>含商业秘密保护、技术文件管理、员工IP归属约定</td></tr><tr><td>IA2</td><td>员工保密协议模板（NDA）</td><td></td></tr><tr><td>IA3</td><td>员工知识产权归属承诺书模板</td><td>确保职务发明归属企业</td></tr><tr><td>IA4</td><td>离职员工交接和保密提示程序</td><td></td></tr><tr><td>IA5</td><td>IP相关培训记录（过去12个月）</td><td></td></tr></tbody></table><h3 id="b-技术文件访问控制" tabindex="-1">B. 技术文件访问控制 <a class="header-anchor" href="#b-技术文件访问控制" aria-label="Permalink to &quot;B. 技术文件访问控制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>IB1</td><td>技术文件分级管理制度</td><td></td></tr><tr><td>IB2</td><td>授权用户列表（有权访问客户技术文件的人员名单）</td><td>现场审核时核查实际系统权限</td></tr><tr><td>IB3</td><td>文件服务器权限截图（现场演示）</td><td>重点：是否限制下载/打印</td></tr><tr><td>IB4</td><td>最近一次权限审查记录</td><td></td></tr></tbody></table><h3 id="c-商标与品牌保护文件" tabindex="-1">C. 商标与品牌保护文件 <a class="header-anchor" href="#c-商标与品牌保护文件" aria-label="Permalink to &quot;C. 商标与品牌保护文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>IC1</td><td>现有商标注册证（如供应商有自有品牌）</td><td></td></tr><tr><td>IC2</td><td>防伪标识的申领/使用台账</td><td></td></tr><tr><td>IC3</td><td>原材料和关键零部件的正品来源证明（采购发票/供应商认证）</td><td></td></tr></tbody></table><h3 id="d-生产管控文件" tabindex="-1">D. 生产管控文件 <a class="header-anchor" href="#d-生产管控文件" aria-label="Permalink to &quot;D. 生产管控文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>ID1</td><td>模具/工装台账</td><td>含模具归属标记，用于核查是否存在未授权生产</td></tr><tr><td>ID2</td><td>分包商管理文件（如生产有外包）</td><td>核查分包商是否签署了IP条款</td></tr><tr><td>ID3</td><td>产品序列号/追溯系统说明（如有）</td><td></td></tr></tbody></table><hr><h2 id="清单五-商业道德与财务健康审核文件请求清单" tabindex="-1">清单五：商业道德与财务健康审核文件请求清单 <a class="header-anchor" href="#清单五-商业道德与财务健康审核文件请求清单" aria-label="Permalink to &quot;清单五：商业道德与财务健康审核文件请求清单&quot;">​</a></h2><p>适用：年度供应商道德与财务DD；战略供应商Level 2/3 DD评估</p><h3 id="a-商业道德制度文件" tabindex="-1">A. 商业道德制度文件 <a class="header-anchor" href="#a-商业道德制度文件" aria-label="Permalink to &quot;A. 商业道德制度文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>BA1</td><td>反贿赂与反腐败政策（书面）</td><td></td></tr><tr><td>BA2</td><td>礼品与商务招待政策（书面）</td><td></td></tr><tr><td>BA3</td><td>利益冲突政策和申报记录（过去12个月的汇总，不含个人信息）</td><td></td></tr><tr><td>BA4</td><td>举报渠道说明（热线/邮箱/平台）</td><td>核查其可及性和有效性</td></tr><tr><td>BA5</td><td>反腐败/合规培训记录（过去12个月）</td><td></td></tr><tr><td>BA6</td><td>对自身供应商/代理商进行反腐败筛查的程序说明</td><td></td></tr></tbody></table><h3 id="b-制裁与合规筛查文件" tabindex="-1">B. 制裁与合规筛查文件 <a class="header-anchor" href="#b-制裁与合规筛查文件" aria-label="Permalink to &quot;B. 制裁与合规筛查文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>BB1</td><td>制裁名单筛查程序说明</td><td>包括筛查工具、频率、触发升级的程序</td></tr><tr><td>BB2</td><td>主要股东/UBO（实际受益人）信息</td><td>用于独立核查制裁风险</td></tr><tr><td>BB3</td><td>在过去3年内发生的重大监管调查/处罚记录（如有）</td><td></td></tr></tbody></table><h3 id="c-财务健康文件" tabindex="-1">C. 财务健康文件 <a class="header-anchor" href="#c-财务健康文件" aria-label="Permalink to &quot;C. 财务健康文件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>文件名称</th><th>说明</th></tr></thead><tbody><tr><td>BC1</td><td>近3个财政年度经外部审计的财务报告</td><td>资产负债表、利润表、现金流量表</td></tr><tr><td>BC2</td><td>最近一期管理账目（未经审计，但须为最新数据）</td><td></td></tr><tr><td>BC3</td><td>有息负债明细（银行贷款/债券/关联方借款，含到期日和利率）</td><td></td></tr><tr><td>BC4</td><td>银行授信情况说明（总额、已用额度、未用额度）</td><td></td></tr><tr><td>BC5</td><td>主要资产抵押/质押情况说明</td><td></td></tr><tr><td>BC6</td><td>主要客户集中度说明（前5大客户占营收比例，可匿名）</td><td></td></tr><tr><td>BC7</td><td>重大诉讼/仲裁案件披露（可能影响财务状况者）</td><td></td></tr><tr><td>BC8</td><td>政府补贴依赖情况说明（过去3年补贴总额及对盈利的影响）</td><td></td></tr></tbody></table><blockquote><p><strong>Level 3 深度DD（Z-Score&lt;1.81或存在财务预警信号时）</strong>，额外要求：</p><ul><li>银行授信确认函（由银行直接出具）</li><li>资产评估报告（如有抵押物）</li><li>关联方交易明细（含利率和担保情况）</li><li>核心管理层履历和背景说明</li></ul></blockquote>',56)])])}const B=d(e,[["render",o]]);export{u as __pageData,B as default};
